package rt.ws.security.org.apache.cxf.ws.security.wss4j.policyvalidators;

public class UsernameTokenPolicyValidator extends AbstractTokenPolicyValidator implements TokenPolicyValidator { public boolean validatePolicy ( AssertionInfoMap aim , Message message , Element soapBody , List < WSSecurityEngineResult > results , List < WSSecurityEngineResult > signedResults ) { Collection < AssertionInfo > ais = aim . get ( SP12Constants . USERNAME_TOKEN ) ; if ( ais == null || ais . isEmpty ( ) ) { return true ; } List < WSSecurityEngineResult > utResults = new ArrayList < WSSecurityEngineResult > ( ) ; WSSecurityUtil . fetchAllActionResults ( results , WSConstants . UT , utResults ) ; WSSecurityUtil . fetchAllActionResults ( results , WSConstants . UT_NOPASSWORD , utResults ) ; for ( AssertionInfo ai : ais ) { org . apache . cxf . ws . security . policy . model . UsernameToken usernameTokenPolicy = ( org . apache . cxf . ws . security . policy . model . UsernameToken ) ai . getAssertion ( ) ; ai . setAsserted ( true ) ; if ( ! isTokenRequired ( usernameTokenPolicy , message ) ) { continue ; } if ( utResults . isEmpty ( ) ) { ai . setNotAsserted ( "The received token does not match the token inclusion requirement" ) ; return false ; } if ( ! checkTokens ( usernameTokenPolicy , ai , utResults ) ) { return false ; } } return true ; } public boolean checkTokens ( org . apache . cxf . ws . security . policy . model . UsernameToken usernameTokenPolicy , AssertionInfo ai , List < WSSecurityEngineResult > utResults ) { for ( WSSecurityEngineResult result : utResults ) { UsernameToken usernameToken = ( UsernameToken ) result . get ( WSSecurityEngineResult . TAG_USERNAME_TOKEN ) ; if ( usernameTokenPolicy . isHashPassword ( ) != usernameToken . isHashed ( ) ) { ai . setNotAsserted ( "Password hashing policy not enforced" ) ; return false ; } if ( usernameTokenPolicy . isNoPassword ( ) && usernameToken . getPassword ( ) != null ) { ai . setNotAsserted ( "Username Token NoPassword policy not enforced" ) ; return false ; } if ( usernameTokenPolicy . isRequireCreated ( ) && ( usernameToken . getCreated ( ) == null || usernameToken . isHashed ( ) ) ) { ai . setNotAsserted ( "Username Token Created policy not enforced" ) ; return false ; } if ( usernameTokenPolicy . isRequireNonce ( ) && ( usernameToken . getNonce ( ) == null || usernameToken . isHashed ( ) ) ) { ai . setNotAsserted ( "Username Token Nonce policy not enforced" ) ; return false ; } } return true ; } }